import java.net.URI;
import java.net.http.*;
import com.google.gson.*;

public class WeatherClient {
    public static void main(String[] args) throws Exception {
        // Build the HTTP client (reusable instance)
        HttpClient client = HttpClient.newHttpClient();

        // Build a GET request to the weather API
        HttpRequest request = HttpRequest.newBuilder()
            .uri(URI.create("https://api.weather.gov/points/39.7,-104.9"))
            .build();

        // Send the request and get the response body
        HttpResponse<String> response = client.send(request,
            HttpResponse.BodyHandlers.ofString());

        // Parse JSON response using Gson library
        JsonObject json = JsonParser.parseString(
            response.body()).getAsJsonObject();

        System.out.println("Status: " + response.statusCode());
        System.out.println("City: " + json.get("city").getAsString());
    }
}
// Expected: Status: 200, City: Denver
